rule.example:
import java.security.MessageDigest

class Bad {
    private val md: MessageDigest = MessageDigest.getInstance("SHA-256") // violation

    fun hash(data: ByteArray): ByteArray {
        md.reset()
        return md.digest(data) // race condition if called from multiple threads
    }
}

class Good {
    fun hash(data: ByteArray): ByteArray {
        val md = MessageDigest.getInstance("SHA-256") // ok: new instance per call
        return md.digest(data)
    }
}

class Bad {
    fun handle() {
        try {
            riskyOperation()
        } catch (e: Exception) {
            e.printStackTrace() // violation: use logger instead
        }
    }
}

class GoodSlf4j {
    private val log = org.slf4j.LoggerFactory.getLogger(GoodSlf4j::class.java)

    fun handle() {
        try {
            riskyOperation()
        } catch (e: Exception) {
            log.error("riskyOperation failed", e) // ok: SLF4J
        }
    }
}

class GoodKotlinLogging {
    private val log = io.github.microutils.kotlinlogging.KotlinLogging.logger {}

    fun handle() {
        try {
            riskyOperation()
        } catch (e: Exception) {
            log.error(e) { "riskyOperation failed" } // ok: kotlin-logging (idiomatic)
        }
    }
}

class Bad {
    private val sb: StringBuffer = StringBuffer()   // violation: potential memory leak

    fun append(s: String) = sb.append(s)
}

class Good {
    fun buildMessage(parts: List<String>): String =
        buildString { parts.forEach { append(it) } }  // ok: Kotlin idiomatic buildString{}

    fun buildMessageAlt(parts: List<String>): String {
        val sb = StringBuilder()                       // ok: local variable
        parts.forEach { sb.append(it) }
        return sb.toString()
    }
}

import java.util.ArrayList
import java.util.HashMap

class Bad {
    private val items: ArrayList<String> = ArrayList()    // violation: use MutableList
    private val cache: HashMap<String, Int> = HashMap()  // violation: use MutableMap
}

class Good {
    private val items: MutableList<String> = mutableListOf()  // ok: interface type
    private val cache: MutableMap<String, Int> = mutableMapOf()  // ok: interface type

    fun local() {
        val local: ArrayList<String> = ArrayList()  // ok: local variable
    }
}

