rule.example:
// violation: original exception e is lost
fun bad() {
    try {
        doSomething()
    } catch (e: Exception) {
        throw RuntimeException("msg")  // e not passed
    }
}

// ok: original exception passed as cause
fun good() {
    try {
        doSomething()
    } catch (e: Exception) {
        throw RuntimeException("msg", e)
    }
}

// ok: intentionally ignored
fun expected() {
    try {
        doSomething()
    } catch (ignoredException: Exception) {
        throw RuntimeException("known failure")
    }
}

class Bad {
    fun report(msg: String) {
        System.out.println(msg)       // violation
        System.err.println("error!")  // violation
    }
}

class Good {
    private val log = org.slf4j.LoggerFactory.getLogger(Good::class.java)

    fun report(msg: String) {
        log.info(msg)  // ok
    }
}

