rule.example:
class Bad {
    fun check(list: List<Int>) {
        if (list.size == 0) println("empty")      // violation
        if (list.size != 0) println("not empty")  // violation
        if (list.count() > 0) println("has items")// violation
    }
}

class Good {
    fun check(list: List<Int>) {
        if (list.isEmpty()) println("empty")      // ok
        if (list.isNotEmpty()) println("not empty")// ok
    }
}

import java.nio.charset.Charset
import java.nio.charset.StandardCharsets

class Bad {
    fun encode(s: String): ByteArray {
        return s.toByteArray(Charset.forName("UTF-8"))  // violation
    }
}

class Good {
    fun encode(s: String): ByteArray {
        return s.toByteArray(StandardCharsets.UTF_8)  // ok
    }
}


fun compute(result: Int): Int {
    val result = 42  // violation - shadows parameter 'result'
    return result
}

fun compute2(input: Int): Int {
    val result = input + 1  // no violation - different name
    return result
}
